class Solution:
    def minimumLevels(self, possible):
        n = len(possible)
        score = [1 if x == 1 else -1 for x in possible]
        total = sum(score)
        prefix = 0
        for j in range(n - 1):
            prefix += score[j]
            bob = total - prefix
            if prefix > bob:
                return j + 1
        return -1

