var minimumLevels = function(possible) {
    const n = possible.length;
    const score = possible.map(x => x === 1 ? 1 : -1);
    const total = score.reduce((a, b) => a + b, 0);
    let prefix = 0;
    for (let j = 0; j < n - 1; j++) {
        prefix += score[j];
        if (prefix > total - prefix) return j + 1;
    }
    return -1;
};
